1	type ScenarioResult = { premium?: number; payout?: number };
2	type ScenarioOutput = { results: ScenarioResult[] };
3	
4	type Item = {
5	  type: string;
6	  cursed?: boolean;
7	  enchantment?: number;
8	  material?: string;
9	};
10	type Damage = { itemType: string; amount: number };
11	type Incident = { cause?: string; damages: Damage[] };
12	type Step = {
13	  op: string;
14	  items: Item[];
15	  policy?: number;
16	  incident?: Incident;
17	};
18	type Customer = { yearsWithMHPCO?: number };
19	type Input = { customer?: Customer; steps: Step[] };
20	
21	const HIGHLY_ENCHANTED_MIN = 5;
22	const LOYALTY_MIN_YEARS = 2;
23	
24	const COMPONENT_BLOCK_SIZE = 3;
25	const COMPONENT_BLOCK_PRICE = 60;
26	const COMPONENT_UNIT_PRICE = 25;
27	
28	const COMPONENT_TYPES = ["rune", "moonstone"] as const;
29	
30	const BASE_BY_ITEM_TYPE: Record<string, number> = {
31	  sword: 100,
32	  amulet: 60,
33	  staff: 80,
34	  potion: 40,
35	  rune: COMPONENT_UNIT_PRICE,
36	  moonstone: COMPONENT_UNIT_PRICE,
37	};
38	
39	// Surcharge / discount multipliers expressed as integer percentages so the
40	// pricing arithmetic stays integer-exact until the final divide-and-ceil.
41	const PERCENT_SCALE = 100;
42	const PROCESSING_FEE = 5;
43	const CURSED_MULT_PCT = 150;
44	const HIGHLY_ENCHANTED_MULT_PCT = 130;
45	const LOYALTY_MULT_PCT = 80;
46	const FIRST_CONTRACT_MULT_PCT = 110;
47	const AFTER_FIRST_MULT_PCT = 85;
48	
49	const isComponent = (item: Item): boolean =>
50	  (COMPONENT_TYPES as readonly string[]).includes(item.type);
51	
52	const isHighlyEnchanted = (item: Item): boolean =>
53	  (item.enchantment ?? 0) >= HIGHLY_ENCHANTED_MIN;
54	
55	const hasLoyalty = (customer: Customer | undefined): boolean =>
56	  (customer?.yearsWithMHPCO ?? 0) >= LOYALTY_MIN_YEARS;
57	
58	const isAfterFirstStep = (stepIndex: number): boolean => stepIndex >= 1;
59	
60	const isMultiComponentStep = (step: Step): boolean =>
61	  step.items.length >= 2 && step.items.every(isComponent);
62	
63	const baseForComponentCount = (count: number): number => {
64	  const blocks = Math.floor(count / COMPONENT_BLOCK_SIZE);
65	  const residual = count % COMPONENT_BLOCK_SIZE;
66	  return blocks * COMPONENT_BLOCK_PRICE + residual * COMPONENT_UNIT_PRICE;
67	};
68	
69	const componentStepBase = (step: Step): number =>
70	  COMPONENT_TYPES.reduce((sum, type) => {
71	    const count = step.items.filter((i) => i.type === type).length;
72	    return sum + baseForComponentCount(count);
73	  }, 0);
74	
75	const stepBase = (step: Step): number =>
76	  isMultiComponentStep(step)
77	    ? componentStepBase(step)
78	    : step.items.reduce((sum, i) => sum + BASE_BY_ITEM_TYPE[i.type], 0);
79	
80	const itemSurchargeMultsPct = (item: Item): number[] => {
81	  const mults: number[] = [];
82	  if (item.cursed) mults.push(CURSED_MULT_PCT);
83	  if (isHighlyEnchanted(item)) mults.push(HIGHLY_ENCHANTED_MULT_PCT);
84	  return mults;
85	};
86	
87	const stepMultsPct = (
88	  customer: Customer | undefined,
89	  stepIndex: number,
90	): number[] => {
91	  if (isAfterFirstStep(stepIndex)) return [AFTER_FIRST_MULT_PCT];
92	  const mults: number[] = [];
93	  if (hasLoyalty(customer)) mults.push(LOYALTY_MULT_PCT);
94	  mults.push(FIRST_CONTRACT_MULT_PCT);
95	  return mults;
96	};
97	
98	const applyMultsAndFee = (base: number, multsPct: number[]): number => {
99	  const numerator = multsPct.reduce((n, m) => n * m, base);
100	  const denominator = Math.pow(PERCENT_SCALE, multsPct.length);
101	  return Math.ceil(numerator / denominator) + PROCESSING_FEE;
102	};
103	
104	const quoteStep = (
105	  step: Step,
106	  stepIndex: number,
107	  customer: Customer | undefined,
108	): ScenarioResult => {
109	  const multsPct = [
110	    ...itemSurchargeMultsPct(step.items[0]),
111	    ...stepMultsPct(customer, stepIndex),
112	  ];
113	  return { premium: applyMultsAndFee(stepBase(step), multsPct) };
114	};
115	
116	const CLAIM_DEDUCTIBLE = 100;
117	const DRAGON_REIMBURSEMENT_RATE_PCT = 100;
118	const HIGHLY_ENCHANTED_REIMBURSEMENT_RATE_PCT = 50;
119	
120	const claimStep = (step: Step, steps: Step[]): ScenarioResult => {
121	  const policyStep = steps[step.policy ?? 0];
122	  const reimbursable = (step.incident?.damages ?? []).reduce((sum, damage) => {
123	    const item = policyStep.items.find((i) => i.type === damage.itemType);
124	    let ratePct = 0;
125	    if (item?.material === "dragon") ratePct = DRAGON_REIMBURSEMENT_RATE_PCT;
126	    else if (item && isHighlyEnchanted(item))
127	      ratePct = HIGHLY_ENCHANTED_REIMBURSEMENT_RATE_PCT;
128	    return sum + (damage.amount * ratePct) / PERCENT_SCALE;
129	  }, 0);
130	  return { payout: Math.max(0, reimbursable - CLAIM_DEDUCTIBLE) };
131	};
132	
133	export function runScenario(input: unknown): ScenarioOutput {
134	  const { customer, steps } = input as Input;
135	  const results = steps.map((step, stepIndex) =>
136	    step.op === "claim"
137	      ? claimStep(step, steps)
138	      : quoteStep(step, stepIndex, customer),
139	  );
140	  return { results };
141	}
